script:
frappe.ui.form.on('Sales Invoice', {
    refresh: function(frm) {
        frappe.db.get_single_value('HA POS Settings', 'can_print_invoice').then(function(can_print_invoice) {
            frm.can_print_invoice = can_print_invoice;
            if (can_print_invoice) {
                frm.add_custom_button(__('Print Invoice'), function() {
                    downloadInvoice(frm.doc.name);
                }, __('Actions'));
            }
        });
    },
    on_submit: function(frm) {
        if (frm.doc.docstatus !== 1) return;
        var doDownload = function(can_print) {
            if (can_print) downloadInvoice(frm.doc.name);
        };
        if (frm.can_print_invoice !== undefined) {
            doDownload(frm.can_print_invoice);
        } else {
            frappe.db.get_single_value('HA POS Settings', 'can_print_invoice').then(doDownload);
        }
    }
});

function downloadInvoice(invoiceNumber) {
    var url = frappe.urllib.get_full_url(
        '/api/method/havano_restaurant_pos.api.download_invoice_json?name=' +
        encodeURIComponent(invoiceNumber) + '&receipt_type='
    );
    var a = document.createElement('a');
    a.href = url;
    a.download = invoiceNumber + '.txt';
    a.target = '_blank';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
}

frappe.ui.form.on("Cost Center Details", {
    company_name: function(frm) {
        // reset cost center when company changes
        frm.set_value("cost_center", "");

        // filter cost center options based on selected company
        frm.set_query("cost_center", function() {
            return {
                filters: {
                    company: frm.doc.company_name
                }
            };
        });
    },

    onload: function(frm) {
        if (frm.doc.company_name) {
            frm.set_query("cost_center", function() {
                return {
                    filters: {
                        company: frm.doc.company_name
                    }
                };
            });
        }
    }
});

frappe.ui.form.on("HA POS Settings", {
    onload: function(frm) {
        // set dynamic query for cost_center field in child table
        frm.fields_dict['user_mapping'].grid.get_field('cost_center').get_query = function(doc, cdt, cdn) {
            let row = locals[cdt][cdn];
            return {
                filters: {
                    company_name: row.company  // filter Cost Center Details where company_name matches row's company
                }
            };
        }
    }
});
